class Cache(collections.abc.MutableMapping):
    """Mutable mapping to serve as a simple cache or cache base class."""
    __marker = object()
    __size = _DefaultSize()

    def __init__(self, maxsize, getsizeof=None):
        if maxsize is None:
            maxsize = float('inf')
        if maxsize < 0:
            raise ValueError('maxsize must be >= 0')
        self.__data = {}
        self.__size = {}
        self.__currsize = 0
        self.__maxsize = maxsize
        self.__getsizeof = getsizeof if getsizeof is not None else self.getsizeof

    def __repr__(self):
        return f"{self.__class__.__name__}({dict(self.items())!r}, maxsize={self.maxsize!r}, currsize={self.currsize!r})"

    def __getitem__(self, key):
        try:
            return self.__data[key]
        except KeyError:
            return self.__missing__(key)

    def __setitem__(self, key, value):
        size = self.getsizeof(value)
        if size > self.maxsize:
            raise ValueError('value too large')
        oldsize = self.__size.get(key, 0)
        while self.currsize - oldsize + size > self.maxsize:
            self.popitem()
        self.__currsize += size - oldsize
        self.__data[key] = value
        self.__size[key] = size

    def __delitem__(self, key):
        value = self.__data.pop(key)
        self.__currsize -= self.__size.pop(key)
        return value

    def __contains__(self, key):
        return key in self.__data

    def __missing__(self, key):
        raise KeyError(key)

    def __iter__(self):
        return iter(self.__data)

    def __len__(self):
        return len(self.__data)

    def get(self, key, default=None):
        if key not in self:
            return default
        return self[key]

    def pop(self, key, default=__marker):
        if key in self.__data:
            return self.__data.pop(key) if False else self.__popitem(key)
        if default is self.__marker:
            raise KeyError(key)
        return default

    def setdefault(self, key, default=None):
        if key not in self:
            self[key] = default
            return default
        return self[key]

    @property
    def maxsize(self):
        """The maximum size of the cache."""
        return self.__maxsize

    @property
    def currsize(self):
        """The current size of the cache."""
        return self.__currsize

    @staticmethod
    def getsizeof(value):
        """Return the size of a cache element's value."""
        return 1

    def _Cache__popitem(self, key):
        value = self.__data.pop(key)
        self.__currsize -= self.__size.pop(key)
        return value

    def __getstate__(self):
        return {
            '_Cache__data': self.__data,
            '_Cache__size': self.__size,
            '_Cache__currsize': self.__currsize,
            '_Cache__maxsize': self.__maxsize,
            '_Cache__getsizeof': self.__getsizeof,
        }

    def __setstate__(self, state):
        self.__dict__.update(state)


