    def __init__(self, maxsize, getsizeof=None):
        super().__init__(maxsize, getsizeof)
        self.__order = collections.OrderedDict()

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        self.__order[key] = None

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        del self.__order[key]

    def popitem(self):
        """Remove and return the `(key, value)` pair first inserted."""
        key, _ = self.__order.popitem(last=False)
        return key, self.pop(key)


class LFUCache(Cache):
    """Least Frequently Used (LFU) cache implementation."""

    class _Link:
        __slots__ = ('count', 'keys', 'next', 'prev')

        def __init__(self, count):
            self.count = count
            self.keys = collections.OrderedDict()
            self.next = self.prev = self

        def unlink(self):
            self.prev.next = self.next
            self.next.prev = self.prev
            self.next = self.prev = self

    def __init__(self, maxsize, getsizeof=None):
        super().__init__(maxsize, getsizeof)
        root = self._Link(0)
        self.__root = root
        self.__links = {}

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        value = cache_getitem(self, key)
        self.__touch(key)
        return value

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        cache_setitem(self, key, value)
        self.__touch(key)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        link = self.__links.pop(key)
        del link.keys[key]
        if not link.keys:
            link.unlink()

    def popitem(self):
        """Remove and return the `(key, value)` pair least frequently used."""
        root = self.__root
        if root.next is root:
            raise KeyError(f'{self.__class__.__name__} is empty')
        link = root.next
        key = next(iter(link.keys))
        return key, self.pop(key)

    def __touch(self, key):
        root = self.__root
        link = self.__links.get(key)
        if link is None:
            link = root.next
            if link is root or link.count != 1:
                new = self._Link(1)
                new.prev = root
                new.next = root.next
                root.next.prev = new
                root.next = new
                link = new
            link.keys[key] = None
            self.__links[key] = link
            return
        count = link.count
        next_link = link.next
        if next_link is root or next_link.count != count + 1:
            next_link = self._Link(count + 1)
            next_link.prev = link
            next_link.next = link.next
            link.next.prev = next_link

            link.next.prev = next_link
            link.next = next_link
        del link.keys[key]
        if not link.keys:
            link.unlink()
        next_link.keys[key] = None
        self.__links[key] = next_link


