            if self.__nesting:
                return self.__time
            return self.__timer()

        def __enter__(self):
            if self.__nesting == 0:
                self.__time = self.__timer()
            self.__nesting += 1
            return self.__time

        def __exit__(self, *exc):
            self.__nesting -= 1

        def __reduce__(self):
            return type(self), (self.__timer,)

        def __getattr__(self, name):
