class TTLCache(_TimedCache):
    """LRU Cache implementation with per-item time-to-live (TTL) value."""

    class _Link:
        __slots__ = ('key', 'expires', 'next', 'prev')

        def __init__(self, key=None, expires=None):
            self.key = key
            self.expires = expires
            self.next = self.prev = self

        def __reduce__(self):
            return type(self), (self.key, self.expires)

        def unlink(self):
            self.prev.next = self.next
            self.next.prev = self.prev
            self.next = self.prev = self

    def __init__(self, maxsize, ttl, timer=time.monotonic, getsizeof=None):
        super().__init__(maxsize, timer, getsizeof)
        self.__ttl = ttl
        root = self._Link()
        self.__root = root
        self.__links = {}

    def __contains__(self, key):
        try:
            link = self.__links[key]
        except KeyError:
            return False
        return not (self.timer() >= link.expires)

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        link = self.__links[key]
        if self.timer() >= link.expires:
            return self.__missing__(key)
        with self.timer as time_now:
            self.__links.move_to_end(key)
            self.__getlink(key)
        return cache_getitem(self, key)

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        with self.timer as time_now:
            self.expire(time_now)
            cache_setitem(self, key, value)
        try:
            link = self.__links[key]
        except KeyError:
            link = self._Link(key)
            self.__links[key] = link
        else:
            link.unlink()
        link.expires = time_now + self.__ttl
        root = self.__root
        link.next = root
        link.prev = root.prev
        root.prev.next = link
        root.prev = link

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        link = self.__links.pop(key)
        link.unlink()

    def __iter__(self):
        root = self.__root
        curr = root.next
        time_now = self.timer()
        while curr is not root:
            if time_now < curr.expires:
                yield curr.key
            curr = curr.next

    def __setstate__(self, state):
        self.__dict__.update(state)

    @property
    def ttl(self):
        """The time-to-live value of the cache's items."""
        return self.__ttl

    def expire(self, time=None):
        """Remove expired items from the cache and return an iterable of the
        expired `(key, value)` pairs.

        """
        if time is None:
            time = self.timer()
        root = self.__root
        curr = root.next
        expired = []
        while curr is not root and not (time < curr.expires):
            key = curr.key
            expired.append((key, self.pop(key)))
            curr = root.next
        return expired

    def popitem(self):
        """Remove and return the `(key, value)` pair least recently used that
        has not already expired.

        """
        with self.timer as time_now:
            self.expire(time_now)
            root = self.__root
            if root.next is root:
                raise KeyError(f'{self.__class__.__name__} is empty')
            key = root.next.key
            return key, self.pop(key)

    def __getlink(self, key):
        return self.__links[key]


