        def __lt__(self, other):
            return self.expires < other.expires

    def __init__(self, maxsize, ttu, timer=time.monotonic, getsizeof=None):
        super().__init__(maxsize, timer, getsizeof)
        self.__ttu = ttu
        self.__heap = []
        self.__links = collections.OrderedDict()

    def __contains__(self, key):
        try:
            item = self.__links[key]
        except KeyError:
            return False
        return not item.removed and not (self.timer() >= item.expires)

    def __getitem__(self, key, cache_getitem=Cache.__getitem__):
        item = self.__links[key]
        if item.removed or self.timer() >= item.expires:
            return self.__missing__(key)
        self.__links.move_to_end(key)
        return cache_getitem(self, key)

    def __setitem__(self, key, value, cache_setitem=Cache.__setitem__):
        with self.timer as time_now:
            self.expire(time_now)
            expires = self.__ttu(key, value, time_now)
            if time_now < expires:
                cache_setitem(self, key, value)
                try:
                    old = self.__links[key]
                except KeyError:
                    pass
                else:
                    old.removed = True
                item = self._Item(key, expires)
                self.__links[key] = item
                heapq.heappush(self.__heap, item)

    def __delitem__(self, key, cache_delitem=Cache.__delitem__):
        cache_delitem(self, key)
        item = self.__links.pop(key)
        item.removed = True

    def __iter__(self):
        time_now = self.timer()
        for key, item in self.__links.items():
            if not item.removed and time_now < item.expires:
                yield key

